How about this? It became more code overall, tho:

```python
def _to_ufo_kerning(self, ufo, kerning_data, direction="LTR"):
    """Add .glyphs kerning to an UFO."""

    class_missing_msg = "Non-existent glyph class %s found in kerning rules."
    overwriting_kerning_msg = "Overwriting kerning value for %s."

    for left, pairs in kerning_data.items():
        left, left_is_class = _ufo_class_name(left, direction, "left")
        if left_is_class and left not in ufo.groups:
            self.logger.warning(class_missing_msg % left)

        for right, kerning_val in pairs.items():
            right, right_is_class = _ufo_class_name(right, direction, "right")
            if right_is_class and right not in ufo.groups:
                self.logger.warning(class_missing_msg % right)

            # Emit kerning
            if left in ufo.kerning and right in ufo.kerning[left]:
                self.logger.warning(overwriting_kerning_msg % [left, right])
            ufo.kerning[left, right] = kerning_val


def _ufo_class_name(name, direction, side):
    """Return the UFO class name for a .glyphs class name."""
    if side == "left":
        side_key = "L" if direction == "LTR" else "R"
        side_number = "1"
    else:
        side_key = "R" if direction == "LTR" else "L"
        side_number = "2"

    match = re.match(r"@MMK_" + side_key + r"_(.+)", name)

    name_is_class = bool(match)
    if name_is_class:
        name = "public.kern%s.%s" % (side_number, match.group(1))
        if direction == "RTL":
            name += ".RTL"

    return name, name_is_class
```

